use std::io;

fn read_line() -> String {
    let mut line = String::new();
    io::stdin().read_line(&mut line).unwrap();
    line
}

fn main() {

    let luckies = vec![4, 7, 44, 47, 74, 77, 444, 447, 474, 477, 744, 747, 774, 777];
    let n = read_line().trim().parse::<u32>().unwrap();

    if luckies.into_iter().any(|v| n % v == 0) {
        println!("YES");
    } else {
        println!("NO");
    }
}
